mapper.select:
SELECT MAX(last_seen_at)
FROM index_constituent
WHERE index_code = #{indexCode}

mapper.update:
UPDATE index_constituent
SET current_member = FALSE
WHERE index_code = #{indexCode}

mapper.select:
SELECT COUNT(*)
FROM index_constituent
WHERE index_code = #{indexCode}

SELECT i.symbol FROM index_constituent i LEFT JOIN stock_symbol s ON s.symbol = i.symbol WHERE i.current_member = TRUE AND i.symbol NOT IN ('TICKER', 'SECURITY') AND UPPER(COALESCE(i.sector, '')) <> 'TICKER' AND i.index_code IN
#{indexCode}
GROUP BY i.symbol ORDER BY MAX(CASE WHEN s.last_collected_at IS NULL THEN 1 ELSE 0 END) DESC, MIN(s.last_collected_at), i.symbol LIMIT #{limit}

SELECT p.symbol, p.name, p.logo, ic.sector, p.finnhub_industry AS industry, p.market_cap, q.current_price, q.previous_close, q.open_price, q.high_price, q.low_price, m.pe_normalized_annual, m.pb_annual, m.roe_ttm, sl.integrated_score AS signalScore, sl.confidence AS signalConfidence, sl.tone AS signalTone, sl.calculated_at AS signalCalculatedAt FROM company_profile p LEFT JOIN ( SELECT symbol, MIN(sector) AS sector FROM index_constituent WHERE current_member = TRUE GROUP BY symbol ) ic ON ic.symbol = p.symbol LEFT JOIN stock_quote_cache q ON q.symbol = p.symbol LEFT JOIN stock_metric_snapshot m ON m.symbol = p.symbol AND m.metric_date = ( SELECT MAX(metric_date) FROM stock_metric_snapshot WHERE symbol = p.symbol ) LEFT JOIN stock_signal_latest sl ON sl.symbol = p.symbol WHERE p.symbol IN
#{symbol}
ORDER BY p.market_cap DESC, p.symbol
